export const hasTranslation = (key: string): boolean => messages[key] !== undefined;

const interpolate = (value: string, values?: Record<string, string | number>) => {
  if (values === undefined) return value;
  return Object.entries(values).reduce(
    (current, [key, replacement]) => current.replaceAll(`{${key}}`, String(replacement)),
    value,
  );
};

export const translateMessage = (
  key: string,
  locale: Locale,
  values?: Record<string, string | number>,
): string => interpolate(locale === "ko" ? key : messages[key]?.[locale] ?? key, values);

export const useI18n = () => {
  const { settings } = useSettings();
  const locale = resolveAppLanguage(settings.language);

  return useMemo(() => ({
    locale,
    t: (key: string, values?: Record<string, string | number>) =>
      translateMessage(key, locale, values),
    formatNumber: (value: number) => new Intl.NumberFormat(locale).format(value),
    formatDate: (value: string | number | Date) => new Intl.DateTimeFormat(locale, {
      year: "numeric",
      month: "short",
      day: "numeric",
    }).format(new Date(value)),
    formatKstDate: (value: string | number | Date) => new Intl.DateTimeFormat(locale, {
      year: "numeric",
      month: "short",
      day: "numeric",
      timeZone: "Asia/Seoul",
    }).format(new Date(value)),
  }), [locale]);
};
